// MOC Reference Images — real game assets for visual consistency
// Categories: cannon | gate | champion | mechanic | biome
// These are sent to Gemini as visual anchors for every render call

export interface MOCReference {
  key: string;
  category: "cannon" | "gate" | "champion" | "mechanic" | "biome";
  label: string;
  base64: string;
  mimeType?: string;
}

