// Build a text context summary of available refs (used in analysis prompts)
export function buildReferenceContext(): string {
  const byCategory = MOC_REFERENCES.reduce((acc, ref) => {
    if (!acc[ref.category]) acc[ref.category] = [];
    acc[ref.category].push(ref.label);
    return acc;
  }, {} as Record<string, string[]>);
  return Object.entries(byCategory)
    .map(([cat, labels]) => `${cat.toUpperCase()}: ${labels.join(", ")}`)
    .join("\n");
}

// Build inline image parts for Gemini multimodal calls
export function buildReferenceParts(keys: string[]): any[] {
  const parts: any[] = [];
  for (const key of keys) {
    const ref = MOC_REFERENCES.find(r => r.key === key);
    if (ref && !ref.base64.startsWith("REPLACE_")) {
      parts.push({ text: `[REF: ${ref.label}]` });
      parts.push({ inlineData: { mimeType: ref.mimeType || "image/png", data: ref.base64 } });
    }
  }
  return parts;
}
